const row = $json;

// ─── EDIT THESE TWO ───────────────────────────────────────────
const SLACK_TOKEN   = 'xoxb-REPLACE-WITH-YOUR-BOT-TOKEN';
const SLACK_CHANNEL = 'C07532VA22X';
const RECORDINGS_ROOT = 'https://drive.google.com/drive/folders/1wz0iV5CTBquCRj8AlT6Yu4DQLa5fpfwv';
// ──────────────────────────────────────────────────────────────

// "83%" or "72" -> 83 / 72 ; blank/NaN -> null
function num(v) { const n = parseFloat(String(v == null ? '' : v)); return isNaN(n) ? null : n; }
// "28/37" -> 75.67 (percent) ; unparseable / zero denominator -> null
function frac(v) { const p = String(v == null ? '' : v).split('/'); const a = parseFloat(p[0]); const b = parseFloat(p[1]); return (b && !isNaN(a)) ? (a / b) * 100 : null; }
// Overall flag: green Pass >= 70, yellow Review >= 50, else red Fail
function passFlag(p) { if (p == null) return { e: '⚪', l: 'N/A' }; if (p >= 70) return { e: '🟢', l: 'Pass' }; if (p >= 50) return { e: '🟡', l: 'Review' }; return { e: '🔴', l: 'Fail' }; }
// Essay flag: green Excellent >= 80, yellow Good >= 60, else red Needs work
function essayFlag(p) { if (p == null) return { e: '⚪', l: 'N/A' }; if (p >= 80) return { e: '🟢', l: 'Excellent' }; if (p >= 60) return { e: '🟡', l: 'Good' }; return { e: '🔴', l: 'Needs work' }; }

const name     = row['Candidate Email'] || row['Code'] || 'Applicant';
const code     = String(row['Code'] == null ? '' : row['Code']).trim();
const objScore = row['Objective Score'] || '';
const objPct   = row['Objective %'] || '';
const essScore = row['Essay Score'] || '';
const essPct   = row['Essay %'] || '';
const overall  = row['Overall Score'] || '';

const oPct    = frac(overall);
const oFlag   = passFlag(oPct);
const eFlag   = essayFlag(num(essPct));
const oPctStr = oPct == null ? '—' : Math.round(oPct) + '%';

const slackText =
  oFlag.e + '  *' + name + ' — completed the assessment*\n\n' +
  '*Objective Score:*  ' + objScore + '  (' + objPct + ')\n' +
  '*Essay Score:*  ' + essScore + '  (' + essPct + ')  →  ' + eFlag.e + ' ' + eFlag.l + '\n' +
  '*Overall Score:*  ' + overall + '  (' + oPctStr + ')  →  ' + oFlag.e + ' ' + oFlag.l;

const threadText =
  '📹 Recording: ' + RECORDINGS_ROOT + '\n_Open the subfolder named_  *' + name + ' — ' + code + '*';

return { json: { slackToken: SLACK_TOKEN, slackChannel: SLACK_CHANNEL, slackText: slackText, threadText: threadText } };
